**Gatling Scala/Java DSL:**

```java
// PaymentLoadTest.java:
public class PaymentLoadTest extends Simulation {
    HttpProtocolBuilder http = HttpDsl.http
        .baseUrl("http://localhost:8080")
        .acceptHeader("application/json");

    ScenarioBuilder scn = CoreDsl.scenario("Payment load")
        .exec(HttpDsl.http("POST payment")
            .post("/api/payments")
            .header("Content-Type", "application/json")
            .header("X-API-Key", "rzp_test_abc")
            .body(StringBody("{\"amount\": 5000, \"gateway\": \"HDFC\"}"))
            .check(HttpDsl.status().is(200))
            .check(HttpDsl.responseTimeInMillis().lte(500)));

    { setUp(
        scn.injectOpen(
            CoreDsl.atOnceUsers(10),              // 10 users immediately
            CoreDsl.rampUsers(100).during(30),     // ramp 100 over 30s
            CoreDsl.constantUsersPerSec(50).during(60) // 50/s for 60s
        ).protocols(http)
    ).assertions(
        CoreDsl.global().responseTime().percentile3().lt(500),  // p99 < 500ms
        CoreDsl.global().successfulRequests().percent().gt(99.0) // >99% success
    ); }
}
```

